<?php
require_once __DIR__.'/../../includes/ecosystem.php';$wallet=beyond_app_bootstrap('Beyond Wallet');global $pdo;$transactions=[];try{$stmt=$pdo->prepare('SELECT t.* FROM beyond_wallet_transactions t JOIN beyond_wallets w ON w.id=t.wallet_id WHERE w.user_id=? ORDER BY t.created_at DESC LIMIT 50');$stmt->execute([(int)$_SESSION['user_id']]);$transactions=$stmt->fetchAll(PDO::FETCH_ASSOC);}catch(Throwable $e){}
?><!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Beyond Wallet | Beyond OS 2.1 Beta</title><link rel="stylesheet" href="../assets/css/admin-v2.css?v=2.1.4"><style>.wallet-hero{background:linear-gradient(135deg,#29245f,#7d297b,#c03971)}.wallet-hero h1{font-size:clamp(42px,8vw,72px);margin:12px 0}.content{max-width:950px;margin:auto}.receipt{display:flex;justify-content:space-between;gap:12px;padding:15px 0;border-bottom:1px solid var(--border)}@media(max-width:560px){.content{padding:16px}.receipt{align-items:flex-start;flex-direction:column}}</style></head><body><main class="content"><div class="card wallet-hero"><span class="badge">BEYOND BITS</span><h1><?=number_format((float)$wallet['balance'],0)?> <?=e($wallet['currency'])?></h1><p>Your reward balance follows your Beyond ID across every app.</p></div><div class="card" style="margin-top:16px"><h2>Activity</h2><?php if(!$transactions):?><p class="muted">No wallet activity yet. Complete your profile to earn your first 100 bit$.</p><?php endif;?><?php foreach($transactions as $item):?><div class="receipt"><span><?=e($item['description']?:$item['app_slug'])?><br><small class="muted"><?=e($item['created_at'])?></small></span><strong><?=$item['type']==='credit'?'+':'−'?><?=number_format(abs((float)$item['amount']),0)?> bit$</strong></div><?php endforeach;?></div></main></body></html>
